SELECT COUNT(*) AS deprecated_srs_count
FROM spatial_reference_systems
WHERE deprecated = 1;

SELECT srs_id, description, projection_acronym, ellipsoid_acronym
FROM spatial_reference_systems
WHERE is_geo = 1;

SELECT description
FROM spatial_reference_systems
WHERE updated_at = (
  SELECT MAX(updated_at)
  FROM spatial_reference_systems
);
